const body = $input.first().json.body || $input.first().json;
const ticker = (body.ticker || '').toUpperCase().trim();
if (!ticker || ticker.length > 6) throw new Error('INVALID_TICKER');
const ind = {
  ticker,
  price: parseFloat(body.price) || 0,
  change: parseFloat(body.change) || 0,
  changePct: parseFloat(body.changePct) || 0,
  rsi: parseFloat(body.rsi) || 50,
  macd: parseFloat(body.macd) || 0,
  macdSignal: parseFloat(body.macdSignal) || 0,
  macdHist: parseFloat(body.macdHist) || 0,
  ema20: parseFloat(body.ema20) || 0,
  ema50: parseFloat(body.ema50) || 0,
  bbUpper: parseFloat(body.bbUpper) || 0,
  bbMiddle: parseFloat(body.bbMiddle) || 0,
  bbLower: parseFloat(body.bbLower) || 0,
  bbPosition: parseFloat(body.bbPosition) || 0.5,
  atr: parseFloat(body.atr) || 0,
  obvTrend: body.obvTrend || 'NEUTRAL',
  volRatio: parseFloat(body.volRatio) || 1,
  high52: parseFloat(body.high52) || 0,
  low52: parseFloat(body.low52) || 0,
  lastDate: body.lastDate || 'N/A',
  roc10: parseFloat(body.roc10) || 0
};
ind.emaCross = ind.ema20 > ind.ema50 ? 'BULLISH' : 'BEARISH';
ind.distFromHigh = ind.high52 > 0 ? (((ind.price - ind.high52) / ind.high52) * 100).toFixed(1) : 'N/A';
ind.distFromLow = ind.low52 > 0 ? (((ind.price - ind.low52) / ind.low52) * 100).toFixed(1) : 'N/A';
return [{ json: ind }];

