const raw = $input.first().json.choices?.[0]?.message?.content || '';
let parsed;
try {
  const cleaned = raw.replace(/```json\n?|\n?```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { signal: 'STAND ASIDE', confidence: 50, correlationScore: 50, vcGateScore: 50,
    reasons: ['Analysis inconclusive — monitor for confirmation signals before entering.',
      'EMA trend unclear — wait for cross confirmation.',
      'RSI in neutral zone — no high-probability entry identified.',
      'Volume not confirming directional move — stand aside.'],
    tradePlan: null, standAsideConditions: ['Wait for EMA20/EMA50 cross confirmation.'],
    marketContext: 'Mixed signals — no clear edge at current levels.' };
}
const colorMap = {
  'BUY': { color: '#00E599', glow: 'rgba(0,229,153,0.35)' },
  'SELL': { color: '#FF4D4D', glow: 'rgba(255,77,77,0.35)' },
  'STAND ASIDE': { color: '#FFB547', glow: 'rgba(255,181,71,0.35)' }
};
parsed.meta = colorMap[parsed.signal] || colorMap['STAND ASIDE'];
parsed.poweredBy = 'Grok-3 · AgilityServ Quantum Pipeline';
return [{ json: parsed }];
